code.python:
def single_number(nums):
    seen = set()
    for n in nums:
        if n in seen:
            seen.discard(n)
        else:
            seen.add(n)
    return next(iter(seen))

code.javascript:
function singleNumber(nums) {
  const seen = new Set();
  for (const n of nums) {
    if (seen.has(n)) {
      seen.delete(n);
    } else {
      seen.add(n);
    }
  }
  return seen.values().next().value;
}

